from haystack import Pipeline
from haystack.components.builders import CustomComponent
from vex import Guard

class VexTenantGuard(CustomComponent):
    def __init__(self):
        self.guards = [
            Guard('tenant_isolation').require('tenant_id').in_context(),
            Guard('retriever_relevance').require('score').gte(0.8)
        ]

    @Component.input_types(tenant_id=str, documents=list)
    @Component.output_types(passed=bool, documents=list)
    def run(self, tenant_id: str, documents: list):
        result = self.guards.run({
            'tenant_id': tenant_id,
            'documents': documents
        })
        return {'passed': result.passed, 'documents': documents if result.passed else []}

# Usage in pipeline
pipeline = Pipeline()
pipeline.add_component('vex_guard', VexTenantGuard())
pipeline.connect('retriever', 'vex_guard.documents')
pipeline.connect('vex_guard.passed', 'generator')
